DROP TABLE IF EXISTS `literature_driver_variants_v1_snapshot`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `literature_driver_variants_v1_snapshot` (
  `literature_variant_id` bigint NOT NULL DEFAULT '0',
  `study_id` bigint NOT NULL,
  `study_name_short` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `gene_symbol` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL,
  `protein_change` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `cDNA_HGVS` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `paper_ref_genome_id` bigint DEFAULT NULL,
  `paper_chrom` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `paper_pos` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `paper_ref` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `paper_alt` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `lifted_ref_genome_id` bigint DEFAULT NULL,
  `lifted_chrom` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `lifted_pos` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `lifted_ref` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `lifted_alt` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `variant_type` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_driver` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL,
  `disease_id` bigint NOT NULL,
  `cell_type_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `evidence_type` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `Remarks` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `natural_key_sha` binary(32) DEFAULT NULL,
  PRIMARY KEY (`literature_variant_id`),
  UNIQUE KEY `uq_ldv_v1_natural_hash` (`natural_key_sha`),
  KEY `idx_ldv_v1_gene` (`gene_symbol`),
  KEY `idx_ldv_v1_disease` (`disease_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

