DROP TABLE IF EXISTS `literature_variant_study`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `literature_variant_study` (
  `literature_variant_study_id` bigint NOT NULL AUTO_INCREMENT,
  `literature_variant_id` bigint NOT NULL,
  `study_id` bigint NOT NULL,
  `evidence_type` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`literature_variant_study_id`),
  UNIQUE KEY `uq_lvs_variant_study` (`literature_variant_id`,`study_id`),
  KEY `fk_lvs_study` (`study_id`),
  CONSTRAINT `fk_lvs_study` FOREIGN KEY (`study_id`) REFERENCES `study` (`study_id`),
  CONSTRAINT `fk_lvs_variant` FOREIGN KEY (`literature_variant_id`) REFERENCES `literature_driver_variants` (`literature_variant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=529 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

