  `variant_type` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `variant_type_norm` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `variant_impact` enum('missense','nonsense','splice','synonymous','noncoding','frameshift','inframe indel','frameshift insertion','frameshift deletion','frameshift delins','inframe insertion','inframe deletion','inframe delins','intron','utr','promoter','intergenic','unknown') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `is_driver` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL,
  `disease_id` bigint NOT NULL,
  `cell_type_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
