  `notes` text COLLATE utf8mb4_unicode_ci,
  `Remarks` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `natural_key_sha` binary(32) GENERATED ALWAYS AS (unhex(sha2(concat_ws(_utf8mb4'|',`study_id`,coalesce(`gene_symbol`,_utf8mb4''),coalesce(`cDNA_HGVS`,_utf8mb4''),coalesce(`protein_change`,_utf8mb4''),coalesce(`paper_chrom`,_utf8mb4''),coalesce(`paper_pos`,_utf8mb4''),coalesce(`paper_ref`,_utf8mb4''),coalesce(`paper_alt`,_utf8mb4''),coalesce(`disease_id`,_utf8mb4''),coalesce(`cell_type_name`,_utf8mb4'')),256))) STORED,
  PRIMARY KEY (`literature_variant_id`),
