  CONSTRAINT `stg_zhu_cell2019_v2_chk_2` CHECK (((`variant_type_norm` is null) or (`variant_type_norm` in (_utf8mb4'SNV',_utf8mb4'Insertion',_utf8mb4'Deletion',_utf8mb4'Indel',_utf8mb4'MNV'))))
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
