/*!50013 DEFINER=`root`@`localhost` SQL SECURITY DEFINER */
/*!50001 VIEW `v_literature_variants_flat` AS select `ldv`.`literature_variant_id` AS `literature_variant_id`,`ldv`.`study_id` AS `study_id`,`s`.`study_name` AS `study_name`,`ldv`.`study_name_short` AS `study_name_short`,`ldv`.`gene_symbol` AS `gene_symbol`,`ldv`.`cDNA_HGVS` AS `cDNA_HGVS`,`ldv`.`protein_change` AS `protein_change`,concat(coalesce(`ldv`.`lifted_chrom`,`ldv`.`paper_chrom`),':',coalesce(`ldv`.`lifted_pos`,`ldv`.`paper_pos`),' ',coalesce(`ldv`.`lifted_ref`,`ldv`.`paper_ref`),'>',coalesce(`ldv`.`lifted_alt`,`ldv`.`paper_alt`)) AS `genomic_variant`,(case when ((coalesce(`ldv`.`lifted_ref`,`ldv`.`paper_ref`) is null) or (coalesce(`ldv`.`lifted_alt`,`ldv`.`paper_alt`) is null)) then NULL when ((char_length(coalesce(`ldv`.`lifted_ref`,`ldv`.`paper_ref`)) = 1) and (char_length(coalesce(`ldv`.`lifted_alt`,`ldv`.`paper_alt`)) = 1)) then 'SNV' when (char_length(coalesce(`ldv`.`lifted_ref`,`ldv`.`paper_ref`)) < char_length(coalesce(`ldv`.`lifted_alt`,`ldv`.`paper_alt`))) then 'Insertion' when (char_length(coalesce(`ldv`.`lifted_ref`,`ldv`.`paper_ref`)) > char_length(coalesce(`ldv`.`lifted_alt`,`ldv`.`paper_alt`))) then 'Deletion' else 'Indel' end) AS `variant_type`,`ldv`.`variant_impact` AS `consequence_detail`,(case when (`ldv`.`variant_impact` is null) then 'Unknown' when (`ldv`.`variant_impact` = 'unknown') then 'Unknown' when (`ldv`.`variant_impact` like 'frameshift%') then 'Frameshift' when (`ldv`.`variant_impact` like 'inframe%') then 'Inframe indel' when (`ldv`.`variant_impact` = 'frameshift') then 'Frameshift' when (`ldv`.`variant_impact` = 'inframe indel') then 'Inframe indel' when (`ldv`.`variant_impact` = 'missense') then 'Missense' when (`ldv`.`variant_impact` = 'nonsense') then 'Nonsense' when (`ldv`.`variant_impact` = 'splice') then 'Splice' when (`ldv`.`variant_impact` = 'synonymous') then 'Synonymous' when (`ldv`.`variant_impact` = 'noncoding') then 'Noncoding' when (`ldv`.`variant_impact` = 'intron') then 'Intron' when (`ldv`.`variant_impact` = 'utr') then 'UTR' when (`ldv`.`variant_impact` = 'promoter') then 'Promoter' when (`ldv`.`variant_impact` = 'intergenic') then 'Intergenic' else 'Unknown' end) AS `consequence`,`ldv`.`is_driver` AS `is_driver`,`d`.`disease_id` AS `disease_id`,`d`.`disease_name` AS `disease_name`,`d`.`category` AS `disease_category`,`d`.`disease_ontology_id` AS `disease_ontology_id`,`ldv`.`cell_type_name` AS `cell_type_name`,`ct`.`cell_type_ontology_id` AS `cell_type_ontology_id`,`ldv`.`evidence_type` AS `evidence_type`,`ldv`.`notes` AS `notes`,`ldv`.`Remarks` AS `Remarks`,`rgp`.`ref_genome_name` AS `paper_ref_genome`,`ldv`.`paper_chrom` AS `paper_chrom`,`ldv`.`paper_pos` AS `paper_pos`,`ldv`.`paper_ref` AS `paper_ref`,`ldv`.`paper_alt` AS `paper_alt`,`rgl`.`ref_genome_name` AS `lifted_ref_genome`,`ldv`.`lifted_chrom` AS `lifted_chrom`,`ldv`.`lifted_pos` AS `lifted_pos`,`ldv`.`lifted_ref` AS `lifted_ref`,`ldv`.`lifted_alt` AS `lifted_alt` from (((((`literature_driver_variants` `ldv` join `study` `s` on((`s`.`study_id` = `ldv`.`study_id`))) join `disease` `d` on((`d`.`disease_id` = `ldv`.`disease_id`))) left join `cell_type` `ct` on((`ct`.`cell_type_name` = `ldv`.`cell_type_name`))) left join `reference_genome` `rgp` on((`rgp`.`ref_genome_id` = `ldv`.`paper_ref_genome_id`))) left join `reference_genome` `rgl` on((`rgl`.`ref_genome_id` = `ldv`.`lifted_ref_genome_id`))) */;
